// src/routes/AppRoutes.js
import Login from "../pages/auth/Login";
import Register from "../pages/auth/Register";
import { Routes, Route, Navigate } from "react-router-dom";

import AdminDashboard from "../pages/dashboard/AdminDashboard";
import InstructorDashboard from "../pages/dashboard/InstructorDashboard";
import StudentDashboard from "../pages/dashboard/StudentDashboard";
import ContentDashboard from "../pages/dashboard/ContentDashboard";

import Protected from "../components/Protected";


// Centralized 404 Page (Fallback for undefined routes)
const NotFound = () => (
  <div
    style={{
      display: "flex",
      flexDirection: "column",
      justifyContent: "center",
      alignItems: "center",
      height: "80vh",
      textAlign: "center",
      padding: "20px",
    }}
  >
    <h1 style={{ fontSize: "2.5rem", color: "#ef4444", marginBottom: "15px" }}>
      404 - Page Not Found
    </h1>
    <p style={{ color: "#374151", fontSize: "1.1rem", marginBottom: "20px" }}>
      The page you are looking for does not exist.
    </p>
    <a
      href="/"
      style={{
        color: "#a71010",
        fontWeight: "600",
        textDecoration: "underline",
        cursor: "pointer",
      }}
    >
      Go Back Home
    </a>
  </div>
);

const AppRoutes = () => {
  return (
    <Routes>
      {/* Public Routes */}
      <Route path="/" element={<Login />} />
      <Route path="/register" element={<Register />} />

      {/* Protected Routes */}
      <Route
        path="/admin"
        element={
          <Protected allowedRoles={["admin"]}>
            <AdminDashboard />
          </Protected>
        }
      />
      <Route
        path="/instructor"
        element={
          <Protected allowedRoles={["instructor"]}>
            <InstructorDashboard />
          </Protected>
        }
      />
      <Route
        path="/student"
        element={
          <Protected allowedRoles={["student"]}>
            <StudentDashboard />
          </Protected>
        }
      />
      <Route
        path="/content"
        element={
          <Protected allowedRoles={["content"]}>
            <ContentDashboard />
          </Protected>
        }
      />

      {/* Fallback Route for undefined URLs */}
      <Route path="*" element={<NotFound />} />
    </Routes>
  );
};

export default AppRoutes;
